const config = {
  "previewFeatures": [],
  "clientVersion": "7.1.0",
  "engineVersion": "ab635e6b9d606fa5c8fb8b1a7f909c3c3c1c98ba",
  "activeProvider": "postgresql",
  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n  output   = \"../generated/prisma-client\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// User model (simplified - may integrate with existing auth)\nmodel User {\n  id                 String              @id @default(uuid())\n  email              String              @unique\n  name               String?\n  passwordHash       String?\n  createdAt          DateTime            @default(now())\n  updatedAt          DateTime            @updatedAt\n  personaPreferences PersonaPreference[]\n  workspaces         Workspace[]\n  ownedModels        MlModel[]\n  workflowExecutions WorkflowExecution[]\n  auditEvents        AuditEvent[]\n\n  // User Journey relations\n  requestedApprovals           Approval[]          @relation(\"RequestedApprovals\")\n  approverSteps                ApprovalStep[]      @relation(\"ApproverSteps\")\n  timeOffRequests              TimeOffRequest[]    @relation(\"TimeOffRequests\")\n  performanceReviewsAsEmployee PerformanceReview[] @relation(\"ReviewedEmployee\")\n  performanceReviewsAsReviewer PerformanceReview[] @relation(\"Reviewer\")\n  notifications                Notification[]      @relation(\"UserNotifications\")\n  comments                     Comment[]           @relation(\"CommentAuthor\")\n  restructuresProposed         Restructure[]       @relation(\"RestructureProposer\")\n  growthPlans                  GrowthPlan[]        @relation(\"EmployeeGrowthPlans\")\n  incidentsReported            Incident[]          @relation(\"IncidentReporter\")\n  incidentsAssigned            Incident[]          @relation(\"IncidentAssignee\")\n\n  // Cross-Functional Features\n  articles         Article[]\n  ideas            Idea[]\n  userSkills       UserSkill[]\n  developmentPlans DevelopmentPlan[]\n\n  @@map(\"users\")\n}\n\n// Workspace model - represents a software-org workspace\nmodel Workspace {\n  id          String              @id @default(uuid())\n  name        String\n  slug        String              @unique\n  ownerId     String\n  owner       User                @relation(fields: [ownerId], references: [id], onDelete: Cascade)\n  createdAt   DateTime            @default(now())\n  updatedAt   DateTime            @updatedAt\n  preferences PersonaPreference[]\n  overrides   WorkspaceOverride?\n\n  @@index([ownerId])\n  @@map(\"workspaces\")\n}\n\n// PersonaPreference - stores user's persona configuration per workspace\nmodel PersonaPreference {\n  id          String    @id @default(uuid())\n  userId      String\n  workspaceId String\n  activeRoles Json // Array of active role IDs: [\"admin\", \"tech-lead\"]\n  preferences Json // Persona-specific preferences: { dashboardLayout: {...}, plugins: [...] }\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n  user        User      @relation(fields: [userId], references: [id], onDelete: Cascade)\n  workspace   Workspace @relation(fields: [workspaceId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, workspaceId])\n  @@index([userId])\n  @@index([workspaceId])\n  @@map(\"persona_preferences\")\n}\n\n// WorkspaceOverride - admin-defined workspace-level persona config\nmodel WorkspaceOverride {\n  id          String    @id @default(uuid())\n  workspaceId String\n  overrides   Json // Workspace-level persona overrides: { disabledPlugins: [...], forcedFeatures: [...] }\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n  workspace   Workspace @relation(fields: [workspaceId], references: [id], onDelete: Cascade)\n\n  @@unique([workspaceId])\n  @@index([workspaceId])\n  @@map(\"workspace_overrides\")\n}\n\n// Organization - represents the software organization configuration\nmodel Organization {\n  id          String       @id @default(uuid())\n  name        String\n  namespace   String       @unique\n  displayName String\n  description String?\n  structure   Json // { type: \"hierarchical\", maxDepth: 4 }\n  settings    Json // { defaultTimezone, events, hitl, ai }\n  metadata    Json         @default(\"{}\")\n  createdAt   DateTime     @default(now())\n  updatedAt   DateTime     @updatedAt\n  departments Department[]\n  agents      Agent[]\n  hitlActions HitlAction[]\n\n  @@index([namespace])\n  @@map(\"organizations\")\n}\n\n// Department - represents a department in the organization\nmodel Department {\n  id             String       @id @default(uuid())\n  organizationId String\n  name           String\n  type           String // ENGINEERING, QA, DEVOPS, etc.\n  description    String?\n  status         String       @default(\"ACTIVE\") // ACTIVE, INACTIVE\n  configuration  Json         @default(\"{}\") // Department-specific config\n  kpisJson       Json         @default(\"{}\") // Current KPI values (legacy JSON)\n  metadata       Json         @default(\"{}\")\n  createdAt      DateTime     @default(now())\n  updatedAt      DateTime     @updatedAt\n  organization   Organization @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  agents         Agent[]\n  workflows      Workflow[]\n  kpis           Kpi[]\n  teams          Team[]\n  workItems      WorkItem[]\n  budgets        Budget[]\n\n  @@unique([organizationId, name])\n  @@index([organizationId])\n  @@index([type])\n  @@index([status])\n  @@map(\"departments\")\n}\n\n// Agent - represents an agent in the organization\nmodel Agent {\n  id             String       @id @default(uuid())\n  organizationId String\n  departmentId   String\n  name           String\n  role           String\n  status         String       @default(\"ONLINE\") // ONLINE, OFFLINE, BUSY\n  capabilities   Json         @default(\"[]\") // Array of capability strings\n  configuration  Json         @default(\"{}\") // Agent-specific config\n  metadata       Json         @default(\"{}\")\n  createdAt      DateTime     @default(now())\n  updatedAt      DateTime     @updatedAt\n  organization   Organization @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  department     Department   @relation(fields: [departmentId], references: [id], onDelete: Cascade)\n  hitlActions    HitlAction[]\n\n  @@unique([organizationId, name])\n  @@index([organizationId])\n  @@index([departmentId])\n  @@index([role])\n  @@index([status])\n  @@map(\"agents\")\n}\n\n// Workflow - represents a workflow in a department\nmodel Workflow {\n  id            String              @id @default(uuid())\n  departmentId  String\n  name          String\n  type          String // FEATURE_DEVELOPMENT, CODE_REVIEW, DEPLOYMENT, etc.\n  status        String              @default(\"ACTIVE\") // ACTIVE, INACTIVE, PAUSED\n  configuration Json                @default(\"{}\") // Workflow-specific config\n  metadata      Json                @default(\"{}\")\n  createdAt     DateTime            @default(now())\n  updatedAt     DateTime            @updatedAt\n  department    Department          @relation(fields: [departmentId], references: [id], onDelete: Cascade)\n  executions    WorkflowExecution[]\n  triggers      WorkflowTrigger[]\n  workItems     WorkItem[]\n\n  @@unique([departmentId, name])\n  @@index([departmentId])\n  @@index([type])\n  @@index([status])\n  @@map(\"workflows\")\n}\n\n// WorkItem - represents a work item tracked in DevSecOps stages\nmodel WorkItem {\n  id           String      @id @default(uuid())\n  type         String // FEATURE, BUG, INCIDENT, DEPLOYMENT, etc.\n  title        String\n  description  String?\n  status       String      @default(\"TODO\") // TODO, IN_PROGRESS, BLOCKED, DONE\n  priority     String      @default(\"MEDIUM\") // LOW, MEDIUM, HIGH, CRITICAL\n  stageKey     String // Stage from stageMappings (plan, build, test, etc.)\n  assigneeId   String?\n  tenantId     String? // Multi-tenancy support\n  departmentId String?\n  workflowId   String?\n  metadata     Json        @default(\"{}\") // Additional context\n  dueDate      DateTime?\n  createdAt    DateTime    @default(now())\n  updatedAt    DateTime    @updatedAt\n  department   Department? @relation(fields: [departmentId], references: [id], onDelete: SetNull)\n  workflow     Workflow?   @relation(fields: [workflowId], references: [id], onDelete: SetNull)\n\n  @@index([type])\n  @@index([status])\n  @@index([priority])\n  @@index([stageKey])\n  @@index([assigneeId])\n  @@index([tenantId])\n  @@index([departmentId])\n  @@index([workflowId])\n  @@map(\"work_items\")\n}\n\n// HitlAction - represents a human-in-the-loop action\nmodel HitlAction {\n  id             String       @id @default(uuid())\n  organizationId String\n  agentId        String\n  actionType     String // deployment, code_review, approval, etc.\n  description    String\n  confidence     Float // 0.0 to 1.0\n  state          String       @default(\"PENDING\") // PENDING, APPROVED, REJECTED\n  context        Json         @default(\"{}\") // Action context data\n  submittedAt    DateTime     @default(now())\n  submittedBy    String // Agent ID\n  decidedAt      DateTime?\n  decidedBy      String? // User ID or Agent ID\n  decision       String? // APPROVED, REJECTED\n  comment        String?\n  metadata       Json         @default(\"{}\")\n  createdAt      DateTime     @default(now())\n  updatedAt      DateTime     @updatedAt\n  organization   Organization @relation(fields: [organizationId], references: [id], onDelete: Cascade)\n  agent          Agent        @relation(fields: [agentId], references: [id], onDelete: Cascade)\n\n  @@index([organizationId])\n  @@index([agentId])\n  @@index([state])\n  @@index([actionType])\n  @@index([confidence])\n  @@index([submittedAt])\n  @@map(\"hitl_actions\")\n}\n\n// =============================================================================\n// KPI & Metrics Models\n// =============================================================================\n\n// Kpi - KPI definition with current value snapshot\nmodel Kpi {\n  id           String         @id @default(uuid())\n  key          String         @unique // e.g. \"deployments\", \"change-failure-rate\"\n  name         String // Display name\n  description  String?\n  unit         String // e.g. \"/week\", \"%\", \"h\", \"m\", \"USD/mo\"\n  category     String? // e.g. \"delivery\", \"quality\", \"security\"\n  departmentId String?\n  target       Float? // Target value\n  direction    String         @default(\"higher_is_better\") // higher_is_better, lower_is_better\n  value        Float          @default(0) // Current value\n  trend        Float          @default(0) // Percentage change\n  lastUpdated  DateTime       @default(now())\n  createdAt    DateTime       @default(now())\n  updatedAt    DateTime       @updatedAt\n  department   Department?    @relation(fields: [departmentId], references: [id], onDelete: SetNull)\n  dataPoints   KpiDataPoint[]\n  narratives   KpiNarrative[]\n\n  @@index([key])\n  @@index([departmentId])\n  @@index([category])\n  @@map(\"kpis\")\n}\n\n// KpiDataPoint - time-series data for KPI trends\nmodel KpiDataPoint {\n  id        String   @id @default(uuid())\n  kpiId     String\n  timestamp DateTime\n  value     Float\n  createdAt DateTime @default(now())\n  kpi       Kpi      @relation(fields: [kpiId], references: [id], onDelete: Cascade)\n\n  @@index([kpiId])\n  @@index([timestamp])\n  @@index([kpiId, timestamp])\n  @@map(\"kpi_data_points\")\n}\n\n// KpiNarrative - AI-generated insights for KPIs\nmodel KpiNarrative {\n  id         String   @id @default(uuid())\n  kpiId      String?\n  insight    String // The narrative text\n  confidence Float    @default(0.9) // Confidence score 0-1\n  timeRange  String? // e.g. \"7d\", \"30d\"\n  createdAt  DateTime @default(now())\n  kpi        Kpi?     @relation(fields: [kpiId], references: [id], onDelete: SetNull)\n\n  @@index([kpiId])\n  @@index([createdAt])\n  @@map(\"kpi_narratives\")\n}\n\n// =============================================================================\n// ML Model Monitoring Models\n// =============================================================================\n\n// MlModel - ML model definition\nmodel MlModel {\n  id          String           @id @default(uuid())\n  key         String           @unique // e.g. \"churn-predictor\"\n  name        String\n  description String?\n  type        String           @default(\"classification\") // classification, regression, etc.\n  status      String           @default(\"draft\") // draft, training, deployed, archived\n  ownerUserId String?\n  team        String?\n  useCase     String?\n  createdAt   DateTime         @default(now())\n  updatedAt   DateTime         @updatedAt\n  owner       User?            @relation(fields: [ownerUserId], references: [id], onDelete: SetNull)\n  versions    MlModelVersion[]\n\n  @@index([key])\n  @@index([status])\n  @@index([ownerUserId])\n  @@map(\"ml_models\")\n}\n\n// MlModelVersion - versioned model artifacts\nmodel MlModelVersion {\n  id                  String                   @id @default(uuid())\n  modelId             String\n  version             String // e.g. \"2.3.1\"\n  status              String                   @default(\"current\") // current, previous, archived\n  artifactUri         String?\n  deployedEnvironment String? // e.g. \"production\", \"staging\"\n  accuracy            Float?\n  precision           Float?\n  recall              Float?\n  f1Score             Float?\n  latency             Float? // ms\n  throughput          Float? // requests/sec\n  deployedAt          DateTime?\n  createdAt           DateTime                 @default(now())\n  updatedAt           DateTime                 @updatedAt\n  model               MlModel                  @relation(fields: [modelId], references: [id], onDelete: Cascade)\n  metrics             MlModelMetric[]\n  featureImportances  ModelFeatureImportance[]\n\n  @@unique([modelId, version])\n  @@index([modelId])\n  @@index([status])\n  @@map(\"ml_model_versions\")\n}\n\n// MlModelMetric - point-in-time metrics for model versions\nmodel MlModelMetric {\n  id             String         @id @default(uuid())\n  modelVersionId String\n  name           String // e.g. \"accuracy\", \"latency\"\n  value          Float\n  timestamp      DateTime       @default(now())\n  window         String? // e.g. \"1h\", \"24h\"\n  createdAt      DateTime       @default(now())\n  modelVersion   MlModelVersion @relation(fields: [modelVersionId], references: [id], onDelete: Cascade)\n\n  @@index([modelVersionId])\n  @@index([name])\n  @@index([timestamp])\n  @@map(\"ml_model_metrics\")\n}\n\n// ModelFeatureImportance - feature importance for model versions\nmodel ModelFeatureImportance {\n  id             String         @id @default(uuid())\n  modelVersionId String\n  featureName    String\n  importance     Float // 0-1\n  direction      String? // positive, negative\n  createdAt      DateTime       @default(now())\n  modelVersion   MlModelVersion @relation(fields: [modelVersionId], references: [id], onDelete: Cascade)\n\n  @@unique([modelVersionId, featureName])\n  @@index([modelVersionId])\n  @@map(\"model_feature_importances\")\n}\n\n// =============================================================================\n// Reports & Scheduling Models\n// =============================================================================\n\n// ReportDefinition - report template\nmodel ReportDefinition {\n  id          String           @id @default(uuid())\n  key         String           @unique\n  name        String\n  description String?\n  kpiKeys     Json             @default(\"[]\") // Array of KPI keys included\n  audience    String? // e.g. \"engineering\", \"leadership\"\n  createdAt   DateTime         @default(now())\n  updatedAt   DateTime         @updatedAt\n  schedules   ReportSchedule[]\n  runs        ReportRun[]\n\n  @@index([key])\n  @@map(\"report_definitions\")\n}\n\n// ReportSchedule - when and where reports are delivered\nmodel ReportSchedule {\n  id              String           @id @default(uuid())\n  reportId        String\n  cron            String? // Cron expression\n  frequency       String           @default(\"weekly\") // daily, weekly, monthly\n  dayOfWeek       String? // e.g. \"Monday\"\n  time            String? // e.g. \"09:00\"\n  deliveryChannel String           @default(\"email\") // email, slack, etc.\n  recipients      Json             @default(\"[]\") // Array of email addresses\n  formats         Json             @default(\"[\\\"pdf\\\"]\") // Array of formats\n  enabled         Boolean          @default(true)\n  nextRun         DateTime?\n  createdAt       DateTime         @default(now())\n  updatedAt       DateTime         @updatedAt\n  report          ReportDefinition @relation(fields: [reportId], references: [id], onDelete: Cascade)\n\n  @@index([reportId])\n  @@index([enabled])\n  @@map(\"report_schedules\")\n}\n\n// ReportRun - execution record for reports\nmodel ReportRun {\n  id          String           @id @default(uuid())\n  reportId    String\n  status      String           @default(\"pending\") // pending, running, completed, failed\n  runAt       DateTime         @default(now())\n  completedAt DateTime?\n  summary     String?\n  payloadJson Json             @default(\"{}\") // Generated report content\n  createdAt   DateTime         @default(now())\n  report      ReportDefinition @relation(fields: [reportId], references: [id], onDelete: Cascade)\n\n  @@index([reportId])\n  @@index([status])\n  @@index([runAt])\n  @@map(\"report_runs\")\n}\n\n// =============================================================================\n// Workflow Execution Models\n// =============================================================================\n\n// WorkflowExecution - top-level workflow run\nmodel WorkflowExecution {\n  id              String                  @id @default(uuid())\n  workflowId      String\n  workflowKey     String? // Reference to workflow key\n  triggeredByUser String?\n  status          String                  @default(\"pending\") // pending, running, completed, failed, cancelled\n  startedAt       DateTime                @default(now())\n  finishedAt      DateTime?\n  inputJson       Json                    @default(\"{}\")\n  outputJson      Json                    @default(\"{}\")\n  logs            Json                    @default(\"[]\") // Array of log strings\n  createdAt       DateTime                @default(now())\n  updatedAt       DateTime                @updatedAt\n  workflow        Workflow                @relation(fields: [workflowId], references: [id], onDelete: Cascade)\n  triggeredBy     User?                   @relation(fields: [triggeredByUser], references: [id], onDelete: SetNull)\n  steps           WorkflowExecutionStep[]\n\n  @@index([workflowId])\n  @@index([status])\n  @@index([startedAt])\n  @@map(\"workflow_executions\")\n}\n\n// WorkflowExecutionStep - step-level execution records\nmodel WorkflowExecutionStep {\n  id          String            @id @default(uuid())\n  executionId String\n  stepKey     String\n  name        String\n  status      String            @default(\"pending\") // pending, running, completed, failed, skipped\n  startedAt   DateTime?\n  finishedAt  DateTime?\n  log         String?\n  outputJson  Json              @default(\"{}\")\n  createdAt   DateTime          @default(now())\n  execution   WorkflowExecution @relation(fields: [executionId], references: [id], onDelete: Cascade)\n\n  @@index([executionId])\n  @@index([status])\n  @@map(\"workflow_execution_steps\")\n}\n\n// WorkflowTrigger - trigger configuration for workflows\nmodel WorkflowTrigger {\n  id         String   @id @default(uuid())\n  workflowId String\n  type       String   @default(\"schedule\") // schedule, event, manual\n  config     Json     @default(\"{}\") // Trigger-specific config (cron, event type, etc.)\n  enabled    Boolean  @default(true)\n  createdAt  DateTime @default(now())\n  updatedAt  DateTime @updatedAt\n  workflow   Workflow @relation(fields: [workflowId], references: [id], onDelete: Cascade)\n\n  @@index([workflowId])\n  @@index([type])\n  @@index([enabled])\n  @@map(\"workflow_triggers\")\n}\n\n// =============================================================================\n// Audit & Activity Models\n// =============================================================================\n\n// AuditEvent - cross-cutting audit trail\nmodel AuditEvent {\n  id          String   @id @default(uuid())\n  tenantId    String?\n  actorUserId String?\n  entityType  String // e.g. \"workflow\", \"model\", \"report\", \"persona\"\n  entityId    String\n  action      String // e.g. \"create\", \"update\", \"delete\", \"approve\", \"reject\"\n  decision    String? // For approval flows: approve, defer, reject\n  reason      String?\n  detailsJson Json     @default(\"{}\")\n  timestamp   DateTime @default(now())\n  createdAt   DateTime @default(now())\n  tenant      Tenant?  @relation(fields: [tenantId], references: [id], onDelete: SetNull)\n  actor       User?    @relation(fields: [actorUserId], references: [id], onDelete: SetNull)\n\n  @@index([tenantId])\n  @@index([actorUserId])\n  @@index([entityType])\n  @@index([entityId])\n  @@index([action])\n  @@index([timestamp])\n  @@map(\"audit_events\")\n}\n\n// =============================================================================\n// Tenant & Environment Models\n// =============================================================================\n\n// Tenant - logical tenant for multi-tenancy\nmodel Tenant {\n  id               String             @id @default(uuid())\n  key              String             @unique\n  name             String\n  displayName      String?\n  description      String?\n  status           String             @default(\"active\") // active, suspended, archived\n  plan             String             @default(\"standard\") // free, standard, enterprise\n  createdAt        DateTime           @default(now())\n  updatedAt        DateTime           @updatedAt\n  environments     Environment[]\n  alerts           Alert[]\n  anomalies        Anomaly[]\n  abTests          AbTest[]\n  auditEvents      AuditEvent[]\n  trainingJobs     TrainingJob[]\n  personas         Persona[]\n  roles            Role[]\n  teams            Team[]\n  services         Service[]\n  policies         Policy[]\n  platformSettings PlatformSettings[]\n  integrations     Integration[]\n  interactions     Interaction[]\n  buildWorkflows   BuildWorkflow[]    @relation(\"TenantBuildWorkflows\")\n  buildAgents      BuildAgent[]       @relation(\"TenantBuildAgents\")\n\n  @@index([key])\n  @@index([status])\n  @@map(\"tenants\")\n}\n\n// Environment - environment under a tenant\nmodel Environment {\n  id        String   @id @default(uuid())\n  tenantId  String\n  key       String // dev, staging, production\n  name      String\n  region    String?\n  healthy   Boolean  @default(true)\n  lastCheck DateTime @default(now())\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n  tenant    Tenant   @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  @@unique([tenantId, key])\n  @@index([tenantId])\n  @@map(\"environments\")\n}\n\n// Alert - alerts for tenants\nmodel Alert {\n  id               String    @id @default(uuid())\n  tenantId         String\n  severity         String    @default(\"info\") // info, warning, error, critical, low, medium, high\n  status           String    @default(\"active\") // active, acknowledged, resolved\n  title            String?\n  message          String\n  source           String? // e.g. \"model-monitor\", \"infra\", service name\n  relatedIncidents String[] // Array of incident IDs\n  acknowledgedAt   DateTime?\n  acknowledgedBy   String?\n  resolvedAt       DateTime?\n  resolvedBy       String?\n  snoozedUntil     DateTime?\n  metadata         Json? // Additional context data\n  resolved         Boolean   @default(false) // For backward compatibility\n  timestamp        DateTime  @default(now())\n  createdAt        DateTime  @default(now())\n  updatedAt        DateTime  @updatedAt\n  tenant           Tenant    @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  @@index([tenantId, status])\n  @@index([tenantId, severity, createdAt])\n  @@index([source, createdAt])\n  @@index([severity])\n  @@index([resolved])\n  @@index([timestamp])\n  @@map(\"alerts\")\n}\n\n// Anomaly - detected anomalies\nmodel Anomaly {\n  id            String   @id @default(uuid())\n  tenantId      String\n  metric        String // e.g. \"cpu\", \"latency\", \"error_rate\"\n  value         Float\n  baselineValue Float\n  severity      String   @default(\"medium\") // low, medium, high, critical\n  detectedAt    DateTime @default(now())\n  resolved      Boolean  @default(false)\n  createdAt     DateTime @default(now())\n  tenant        Tenant   @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  @@index([tenantId])\n  @@index([metric])\n  @@index([severity])\n  @@index([detectedAt])\n  @@map(\"anomalies\")\n}\n\n// AbTest - A/B test definitions\nmodel AbTest {\n  id           String    @id @default(uuid())\n  tenantId     String\n  name         String\n  description  String?\n  status       String    @default(\"draft\") // draft, running, stopped, completed\n  startedAt    DateTime?\n  stoppedAt    DateTime?\n  winner       String? // Variant name\n  significance Float?\n  configJson   Json      @default(\"{}\") // Test configuration\n  resultsJson  Json      @default(\"{}\") // Test results\n  createdAt    DateTime  @default(now())\n  updatedAt    DateTime  @updatedAt\n  tenant       Tenant    @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  @@index([tenantId])\n  @@index([status])\n  @@map(\"ab_tests\")\n}\n\n// TrainingJob - ML training jobs\nmodel TrainingJob {\n  id         String    @id @default(uuid())\n  tenantId   String\n  modelId    String // Reference to MlModel\n  status     String    @default(\"queued\") // queued, running, completed, failed\n  progress   Int       @default(0) // 0-100\n  startedAt  DateTime?\n  finishedAt DateTime?\n  configJson Json      @default(\"{}\")\n  logsJson   Json      @default(\"[]\")\n  createdAt  DateTime  @default(now())\n  updatedAt  DateTime  @updatedAt\n  tenant     Tenant    @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  @@index([tenantId])\n  @@index([modelId])\n  @@index([status])\n  @@map(\"training_jobs\")\n}\n\n// =============================================================================\n// Admin: Personas & Roles Models (SOFTWARE_ORG_SEEDED_DATASET.md compliant)\n// =============================================================================\n\n// Persona - represents a human or AI persona in the organization\nmodel Persona {\n  id              String           @id @default(uuid())\n  tenantId        String\n  name            String\n  slug            String\n  type            String           @default(\"human\") // human, ai-agent\n  description     String?\n  primaryTeamId   String?\n  active          Boolean          @default(true)\n  configuration   Json             @default(\"{}\") // Persona-specific config\n  metadata        Json             @default(\"{}\")\n  createdAt       DateTime         @default(now())\n  updatedAt       DateTime         @updatedAt\n  tenant          Tenant           @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  primaryTeam     Team?            @relation(fields: [primaryTeamId], references: [id], onDelete: SetNull)\n  roleAssignments RoleAssignment[]\n  members         PersonaMember[]\n  buildAgents     BuildAgent[]\n\n  @@unique([tenantId, slug])\n  @@index([tenantId])\n  @@index([type])\n  @@index([active])\n  @@map(\"personas\")\n}\n\n// PersonaMember - associates users/agents with personas\nmodel PersonaMember {\n  id         String   @id @default(uuid())\n  personaId  String\n  memberId   String // User or Agent ID\n  memberType String   @default(\"user\") // user, agent\n  createdAt  DateTime @default(now())\n  persona    Persona  @relation(fields: [personaId], references: [id], onDelete: Cascade)\n\n  @@unique([personaId, memberId, memberType])\n  @@index([personaId])\n  @@index([memberId])\n  @@map(\"persona_members\")\n}\n\n// Role - RBAC role definition\nmodel Role {\n  id              String           @id @default(uuid())\n  tenantId        String? // null = global role\n  name            String\n  slug            String\n  description     String?\n  permissions     Json             @default(\"[]\") // Array of permission strings\n  scopes          Json             @default(\"[]\") // Array of scope strings\n  isSystem        Boolean          @default(false) // true for built-in roles\n  active          Boolean          @default(true)\n  createdAt       DateTime         @default(now())\n  updatedAt       DateTime         @updatedAt\n  tenant          Tenant?          @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  roleAssignments RoleAssignment[]\n\n  @@unique([tenantId, slug])\n  @@index([tenantId])\n  @@index([isSystem])\n  @@map(\"roles\")\n}\n\n// RoleAssignment - assigns roles to personas or users\nmodel RoleAssignment {\n  id        String    @id @default(uuid())\n  roleId    String\n  personaId String?\n  userId    String?\n  scope     String? // optional scope: tenantId, environmentId, serviceId\n  grantedBy String?\n  grantedAt DateTime  @default(now())\n  expiresAt DateTime?\n  createdAt DateTime  @default(now())\n  role      Role      @relation(fields: [roleId], references: [id], onDelete: Cascade)\n  persona   Persona?  @relation(fields: [personaId], references: [id], onDelete: Cascade)\n\n  @@index([roleId])\n  @@index([personaId])\n  @@index([userId])\n  @@map(\"role_assignments\")\n}\n\n// =============================================================================\n// Admin: Teams & Services Models\n// =============================================================================\n\n// Team - represents a team within a department\nmodel Team {\n  id             String          @id @default(uuid())\n  tenantId       String\n  departmentId   String\n  name           String\n  slug           String\n  description    String?\n  leadId         String? // User or Persona ID\n  status         String          @default(\"ACTIVE\") // ACTIVE, INACTIVE\n  configuration  Json            @default(\"{}\")\n  metadata       Json            @default(\"{}\")\n  createdAt      DateTime        @default(now())\n  updatedAt      DateTime        @updatedAt\n  tenant         Tenant          @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  department     Department      @relation(fields: [departmentId], references: [id], onDelete: Cascade)\n  services       Service[]\n  personas       Persona[]\n  buildWorkflows BuildWorkflow[]\n\n  @@unique([tenantId, slug])\n  @@index([tenantId])\n  @@index([departmentId])\n  @@index([status])\n  @@map(\"teams\")\n}\n\n// Service - represents a software service\nmodel Service {\n  id                    String                 @id @default(uuid())\n  tenantId              String\n  teamId                String? // owner team\n  name                  String\n  slug                  String\n  description           String?\n  repository            String? // git repository URL\n  status                String                 @default(\"healthy\") // healthy, degraded, down, unknown\n  tier                  String                 @default(\"tier-3\") // tier-1, tier-2, tier-3\n  configuration         Json                   @default(\"{}\")\n  metadata              Json                   @default(\"{}\")\n  createdAt             DateTime               @default(now())\n  updatedAt             DateTime               @updatedAt\n  tenant                Tenant                 @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  team                  Team?                  @relation(fields: [teamId], references: [id], onDelete: SetNull)\n  serviceLinks          ServiceLink[]\n  buildWorkflowServices BuildWorkflowService[]\n  buildAgentServices    BuildAgentService[]\n\n  @@unique([tenantId, slug])\n  @@index([tenantId])\n  @@index([teamId])\n  @@index([status])\n  @@map(\"services\")\n}\n\n// ServiceLink - links services to workflows and agents\nmodel ServiceLink {\n  id         String   @id @default(uuid())\n  serviceId  String\n  targetType String // workflow, agent\n  targetId   String\n  linkType   String   @default(\"uses\") // uses, owned_by, monitored_by\n  createdAt  DateTime @default(now())\n  service    Service  @relation(fields: [serviceId], references: [id], onDelete: Cascade)\n\n  @@unique([serviceId, targetType, targetId])\n  @@index([serviceId])\n  @@index([targetId])\n  @@map(\"service_links\")\n}\n\n// =============================================================================\n// Admin: Interactions Models\n// =============================================================================\n\n// Interaction - defines interaction patterns between departments/teams/personas\nmodel Interaction {\n  id                 String   @id @default(uuid())\n  tenantId           String\n  name               String\n  slug               String\n  displayName        String?\n  description        String?\n  type               String   @default(\"handoff\") // handoff, collaboration, delegation, escalation, consultation, notification\n  status             String   @default(\"active\") // active, draft, disabled\n  sourceDepartmentId String? // Source department for handoff/escalation\n  targetDepartmentId String? // Target department for handoff/collaboration\n  sourceTeamId       String?\n  targetTeamId       String?\n  sourcePersonaId    String?\n  targetPersonaId    String?\n  trigger            Json     @default(\"{}\") // Trigger events (eventType, conditions)\n  protocol           Json     @default(\"{}\") // Protocol config (type, timeout, retry)\n  requirements       Json     @default(\"[]\") // Array of handoff requirements\n  actions            Json     @default(\"[]\") // Actions to take on interaction\n  configuration      Json     @default(\"{}\") // Additional configuration\n  metadata           Json     @default(\"{}\")\n  createdAt          DateTime @default(now())\n  updatedAt          DateTime @updatedAt\n  tenant             Tenant   @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  @@unique([tenantId, slug])\n  @@index([tenantId])\n  @@index([type])\n  @@index([status])\n  @@index([sourceDepartmentId])\n  @@index([targetDepartmentId])\n  @@map(\"interactions\")\n}\n\n// =============================================================================\n// Admin: Policies Models (references agentic-event-processor PatternSpecification)\n// =============================================================================\n\n// Policy - operational policy/guardrail definition\nmodel Policy {\n  id                     String                @id @default(uuid())\n  tenantId               String\n  name                   String\n  slug                   String\n  description            String?\n  type                   String                @default(\"guardrail\") // guardrail, approval, auto-remediation\n  status                 String                @default(\"draft\") // draft, active, disabled\n  patternSpecificationId String? // reference to agentic-event-processor PatternSpecification\n  scope                  Json                  @default(\"{}\") // { environments: [], services: [], teams: [] }\n  configuration          Json                  @default(\"{}\") // policy-specific config\n  triggers               Json                  @default(\"[]\") // event types that trigger this policy\n  actions                Json                  @default(\"[]\") // actions to take when policy matches\n  priority               Int                   @default(0)\n  createdBy              String?\n  activatedAt            DateTime?\n  metadata               Json                  @default(\"{}\")\n  createdAt              DateTime              @default(now())\n  updatedAt              DateTime              @updatedAt\n  tenant                 Tenant                @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  buildWorkflowPolicies  BuildWorkflowPolicy[]\n\n  @@unique([tenantId, slug])\n  @@index([tenantId])\n  @@index([status])\n  @@index([type])\n  @@map(\"policies\")\n}\n\n// =============================================================================\n// Admin: Platform Settings & Integrations Models\n// =============================================================================\n\n// PlatformSettings - tenant or global platform configuration\nmodel PlatformSettings {\n  id        String   @id @default(uuid())\n  tenantId  String? // null = global defaults\n  category  String // general, appearance, localization, ai-agents, notifications\n  settings  Json     @default(\"{}\")\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n  tenant    Tenant?  @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  @@unique([tenantId, category])\n  @@index([tenantId])\n  @@index([category])\n  @@map(\"platform_settings\")\n}\n\n// Integration - third-party integration configuration\nmodel Integration {\n  id              String    @id @default(uuid())\n  tenantId        String\n  type            String // git, ci, observability, ticketing, messaging\n  provider        String // github, gitlab, jenkins, prometheus, jira, slack\n  name            String\n  status          String    @default(\"disconnected\") // connected, disconnected, degraded\n  configuration   Json      @default(\"{}\") // provider-specific config (encrypted secrets)\n  healthDetails   Json      @default(\"{}\") // last health check result\n  lastHealthCheck DateTime?\n  createdAt       DateTime  @default(now())\n  updatedAt       DateTime  @updatedAt\n  tenant          Tenant    @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  @@unique([tenantId, type, provider])\n  @@index([tenantId])\n  @@index([type])\n  @@index([status])\n  @@map(\"integrations\")\n}\n\n// =============================================================================\n// Build: Workflows & Agents Models (NEW - for Build journeys B1-B3)\n// =============================================================================\n\n// BuildWorkflow - automation workflow for Build module\n// Reuses existing pattern/workflow models from agentic-event-processor\nmodel BuildWorkflow {\n  id               String                 @id @default(uuid())\n  tenantId         String\n  name             String\n  slug             String\n  description      String?\n  status           String                 @default(\"draft\") // draft, active, disabled\n  ownerTeamId      String?\n  trigger          Json                   @default(\"{}\") // event trigger configuration\n  steps            Json                   @default(\"[]\") // workflow steps (actions, conditions, approvals)\n  configuration    Json                   @default(\"{}\") // additional workflow config\n  createdBy        String?\n  activatedAt      DateTime?\n  metadata         Json                   @default(\"{}\")\n  createdAt        DateTime               @default(now())\n  updatedAt        DateTime               @updatedAt\n  tenant           Tenant                 @relation(\"TenantBuildWorkflows\", fields: [tenantId], references: [id], onDelete: Cascade)\n  ownerTeam        Team?                  @relation(fields: [ownerTeamId], references: [id], onDelete: SetNull)\n  workflowServices BuildWorkflowService[]\n  workflowPolicies BuildWorkflowPolicy[]\n\n  @@unique([tenantId, slug])\n  @@index([tenantId])\n  @@index([status])\n  @@index([ownerTeamId])\n  @@map(\"build_workflows\")\n}\n\n// BuildWorkflowService - links workflows to services\nmodel BuildWorkflowService {\n  id         String        @id @default(uuid())\n  workflowId String\n  serviceId  String\n  createdAt  DateTime      @default(now())\n  workflow   BuildWorkflow @relation(fields: [workflowId], references: [id], onDelete: Cascade)\n  service    Service       @relation(fields: [serviceId], references: [id], onDelete: Cascade)\n\n  @@unique([workflowId, serviceId])\n  @@index([workflowId])\n  @@index([serviceId])\n  @@map(\"build_workflow_services\")\n}\n\n// BuildWorkflowPolicy - links workflows to policies\nmodel BuildWorkflowPolicy {\n  id         String        @id @default(uuid())\n  workflowId String\n  policyId   String\n  createdAt  DateTime      @default(now())\n  workflow   BuildWorkflow @relation(fields: [workflowId], references: [id], onDelete: Cascade)\n  policy     Policy        @relation(fields: [policyId], references: [id], onDelete: Cascade)\n\n  @@unique([workflowId, policyId])\n  @@index([workflowId])\n  @@index([policyId])\n  @@map(\"build_workflow_policies\")\n}\n\n// BuildAgent - AI agent configuration for Build module\n// Reuses existing agent models from agentic-event-processor\nmodel BuildAgent {\n  id            String              @id @default(uuid())\n  tenantId      String\n  name          String\n  slug          String\n  description   String?\n  type          String // incident-triage, deployment-advisor, code-review, etc.\n  status        String              @default(\"draft\") // draft, active, disabled\n  personaId     String? // linked persona (from Admin)\n  tools         Json                @default(\"[]\") // allowed tools: [\"metrics\", \"incidents\", \"git\", \"ci\"]\n  guardrails    Json                @default(\"{}\") // guardrail configuration\n  configuration Json                @default(\"{}\") // agent-specific config\n  createdBy     String?\n  activatedAt   DateTime?\n  metadata      Json                @default(\"{}\")\n  createdAt     DateTime            @default(now())\n  updatedAt     DateTime            @updatedAt\n  tenant        Tenant              @relation(\"TenantBuildAgents\", fields: [tenantId], references: [id], onDelete: Cascade)\n  persona       Persona?            @relation(fields: [personaId], references: [id], onDelete: SetNull)\n  agentServices BuildAgentService[]\n\n  @@unique([tenantId, slug])\n  @@index([tenantId])\n  @@index([status])\n  @@index([type])\n  @@index([personaId])\n  @@map(\"build_agents\")\n}\n\n// BuildAgentService - links agents to services\nmodel BuildAgentService {\n  id        String     @id @default(uuid())\n  agentId   String\n  serviceId String\n  createdAt DateTime   @default(now())\n  agent     BuildAgent @relation(fields: [agentId], references: [id], onDelete: Cascade)\n  service   Service    @relation(fields: [serviceId], references: [id], onDelete: Cascade)\n\n  @@unique([agentId, serviceId])\n  @@index([agentId])\n  @@index([serviceId])\n  @@map(\"build_agent_services\")\n}\n\n// LogEntry - application logs\nmodel LogEntry {\n  id        String   @id @default(cuid())\n  tenantId  String\n  timestamp DateTime @default(now())\n  level     String // error, warn, info, debug\n  source    String\n  message   String   @db.Text\n  metadata  Json? // Additional context: traceId, spanId, userId, etc.\n  createdAt DateTime @default(now())\n\n  @@index([tenantId, level, timestamp])\n  @@index([tenantId, source, timestamp])\n  @@index([timestamp(sort: Desc)])\n  @@map(\"log_entries\")\n}\n\n// =============================================================================\n// User Journey Models - Approval Workflows, Time Off, Reviews, Budgets, etc.\n// =============================================================================\n\n// Approval - multi-level approval workflow\nmodel Approval {\n  id               String         @id @default(uuid())\n  type             String // restructure, budget, hire, time-off, policy-change, system-config\n  requesterId      String\n  requester        User           @relation(\"RequestedApprovals\", fields: [requesterId], references: [id], onDelete: Cascade)\n  status           String         @default(\"pending\") // pending, in-progress, approved, rejected, cancelled, expired\n  data             Json           @default(\"{}\") // Type-specific data\n  metadata         Json           @default(\"{}\") // Additional context\n  currentStepIndex Int            @default(0)\n  createdAt        DateTime       @default(now())\n  updatedAt        DateTime       @updatedAt\n  completedAt      DateTime?\n  approvalSteps    ApprovalStep[]\n\n  @@index([requesterId])\n  @@index([status])\n  @@index([type])\n  @@index([createdAt])\n  @@map(\"approvals\")\n}\n\n// ApprovalStep - individual step in approval chain\nmodel ApprovalStep {\n  id             String    @id @default(uuid())\n  approvalId     String\n  approval       Approval  @relation(fields: [approvalId], references: [id], onDelete: Cascade)\n  level          Int // 0-indexed step in chain\n  approverId     String?\n  approver       User?     @relation(\"ApproverSteps\", fields: [approverId], references: [id], onDelete: SetNull)\n  role           String // manager, executive, owner, admin\n  status         String    @default(\"pending\") // pending, notified, approved, rejected, skipped\n  decision       String? // approve, reject\n  comment        String?\n  notifiedAt     DateTime?\n  decidedAt      DateTime?\n  reminderSentAt DateTime?\n  createdAt      DateTime  @default(now())\n  updatedAt      DateTime  @updatedAt\n\n  @@index([approvalId])\n  @@index([approverId])\n  @@index([status])\n  @@index([level])\n  @@map(\"approval_steps\")\n}\n\n// TimeOffRequest - employee time-off requests\nmodel TimeOffRequest {\n  id         String   @id @default(uuid())\n  userId     String\n  user       User     @relation(\"TimeOffRequests\", fields: [userId], references: [id], onDelete: Cascade)\n  type       String // vacation, sick, personal, bereavement, parental\n  startDate  DateTime\n  endDate    DateTime\n  days       Float // Number of days (can be fractional for half-days)\n  status     String   @default(\"pending\") // pending, approved, rejected, cancelled\n  conflicts  Json     @default(\"[]\") // Array of conflict objects\n  approvalId String?\n  reason     String?\n  createdAt  DateTime @default(now())\n  updatedAt  DateTime @updatedAt\n\n  @@index([userId])\n  @@index([status])\n  @@index([startDate, endDate])\n  @@index([createdAt])\n  @@map(\"time_off_requests\")\n}\n\n// PerformanceReview - employee performance reviews\nmodel PerformanceReview {\n  id           String    @id @default(uuid())\n  employeeId   String\n  employee     User      @relation(\"ReviewedEmployee\", fields: [employeeId], references: [id], onDelete: Cascade)\n  reviewerId   String\n  reviewer     User      @relation(\"Reviewer\", fields: [reviewerId], references: [id], onDelete: Cascade)\n  period       String // Q1-2025, H1-2025, 2025\n  status       String    @default(\"draft\") // draft, submitted, completed, archived\n  ratings      Json      @default(\"{}\") // Category ratings: { technical: 4.5, collaboration: 4.0 }\n  goals        Json      @default(\"{}\") // Goals and achievements\n  feedback     String?   @db.Text\n  aiInsights   Json? // AI-generated insights\n  strengths    Json      @default(\"[]\") // Array of strength strings\n  improvements Json      @default(\"[]\") // Array of improvement areas\n  createdAt    DateTime  @default(now())\n  updatedAt    DateTime  @updatedAt\n  submittedAt  DateTime?\n  completedAt  DateTime?\n\n  @@index([employeeId])\n  @@index([reviewerId])\n  @@index([period])\n  @@index([status])\n  @@map(\"performance_reviews\")\n}\n\n// Budget - department/team budgets\nmodel Budget {\n  id           String     @id @default(uuid())\n  departmentId String\n  department   Department @relation(fields: [departmentId], references: [id], onDelete: Cascade)\n  year         Int\n  quarter      String? // Q1, Q2, Q3, Q4\n  allocated    Float\n  spent        Float      @default(0)\n  forecasted   Float\n  categories   Json       @default(\"{}\") // Category breakdown: { headcount: {...}, tools: {...} }\n  approvalId   String?\n  status       String     @default(\"draft\") // draft, active, frozen, archived\n  notes        String?    @db.Text\n  createdBy    String?\n  createdAt    DateTime   @default(now())\n  updatedAt    DateTime   @updatedAt\n\n  @@unique([departmentId, year, quarter])\n  @@index([departmentId])\n  @@index([year])\n  @@index([status])\n  @@map(\"budgets\")\n}\n\n// Notification - in-app notifications\nmodel Notification {\n  id        String    @id @default(uuid())\n  userId    String\n  user      User      @relation(\"UserNotifications\", fields: [userId], references: [id], onDelete: Cascade)\n  type      String // approval_needed, approval_decision, review_ready, time_off_approved, budget_alert\n  title     String\n  message   String    @db.Text\n  link      String? // Deep link to related entity\n  priority  String    @default(\"normal\") // low, normal, high, urgent\n  read      Boolean   @default(false)\n  readAt    DateTime?\n  metadata  Json      @default(\"{}\") // Additional context\n  createdAt DateTime  @default(now())\n\n  @@index([userId, read])\n  @@index([userId, createdAt])\n  @@index([type])\n  @@index([priority])\n  @@map(\"notifications\")\n}\n\n// Comment - collaborative comments on entities\nmodel Comment {\n  id         String   @id @default(uuid())\n  entityType String // approval, review, restructure, work-item, budget\n  entityId   String // Polymorphic reference - no FK constraint\n  authorId   String\n  author     User     @relation(\"CommentAuthor\", fields: [authorId], references: [id], onDelete: Cascade)\n  content    String   @db.Text\n  mentions   Json     @default(\"[]\") // Array of user IDs mentioned\n  metadata   Json     @default(\"{}\") // Additional context\n  createdAt  DateTime @default(now())\n  updatedAt  DateTime @updatedAt\n\n  @@index([entityType, entityId])\n  @@index([authorId])\n  @@index([createdAt])\n  @@map(\"comments\")\n}\n\n// Restructure - organization restructuring proposals\nmodel Restructure {\n  id             String    @id @default(uuid())\n  proposerId     String\n  proposer       User      @relation(\"RestructureProposer\", fields: [proposerId], references: [id], onDelete: Cascade)\n  title          String\n  description    String?   @db.Text\n  status         String    @default(\"draft\") // draft, submitted, approved, rejected, implemented\n  type           String // merge-teams, split-team, move-members, create-department, dissolve-department\n  changeData     Json      @default(\"{}\") // Specific changes: { fromTeam, toTeam, members: [...] }\n  impactAnalysis Json      @default(\"{}\") // Affected teams, services, workflows\n  approvalId     String?\n  implementedAt  DateTime?\n  createdAt      DateTime  @default(now())\n  updatedAt      DateTime  @updatedAt\n\n  @@index([proposerId])\n  @@index([status])\n  @@index([type])\n  @@map(\"restructures\")\n}\n\n// GrowthPlan - employee personal growth plans\nmodel GrowthPlan {\n  id          String    @id @default(uuid())\n  userId      String\n  user        User      @relation(\"EmployeeGrowthPlans\", fields: [userId], references: [id], onDelete: Cascade)\n  title       String\n  description String?   @db.Text\n  period      String // Q1-2025, H1-2025, 2025\n  status      String    @default(\"active\") // active, completed, archived\n  goals       Json      @default(\"[]\") // Array of goal objects\n  skills      Json      @default(\"[]\") // Skills to develop\n  resources   Json      @default(\"[]\") // Learning resources\n  progress    Int       @default(0) // 0-100\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n  completedAt DateTime?\n\n  @@index([userId])\n  @@index([status])\n  @@index([period])\n  @@map(\"growth_plans\")\n}\n\n// Incident - incident tracking (for cross-persona workflows)\nmodel Incident {\n  id            String    @id @default(uuid())\n  title         String\n  description   String?   @db.Text\n  severity      String // low, medium, high, critical\n  status        String    @default(\"open\") // open, investigating, resolved, closed\n  reporterId    String\n  reporter      User      @relation(\"IncidentReporter\", fields: [reporterId], references: [id], onDelete: Cascade)\n  assigneeId    String?\n  assignee      User?     @relation(\"IncidentAssignee\", fields: [assigneeId], references: [id], onDelete: SetNull)\n  serviceId     String?\n  affectedUsers Int       @default(0)\n  resolvedAt    DateTime?\n  rootCause     String?   @db.Text\n  remediation   String?   @db.Text\n  timeline      Json      @default(\"[]\") // Timeline of events\n  metadata      Json      @default(\"{}\") // Additional context\n  createdAt     DateTime  @default(now())\n  updatedAt     DateTime  @updatedAt\n\n  @@index([status])\n  @@index([severity])\n  @@index([reporterId])\n  @@index([assigneeId])\n  @@index([createdAt])\n  @@map(\"incidents\")\n}\n\n// ============================================================================\n// Knowledge Base\n// ============================================================================\n\nmodel Article {\n  id          String   @id @default(uuid())\n  title       String\n  content     String   @db.Text\n  summary     String?\n  category    String // e.g., \"engineering\", \"product\"\n  tags        String[]\n  authorId    String\n  author      User     @relation(fields: [authorId], references: [id])\n  views       Int      @default(0)\n  likes       Int      @default(0)\n  isPublished Boolean  @default(false)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  @@map(\"articles\")\n}\n\n// ============================================================================\n// Innovation Tracker\n// ============================================================================\n\nmodel Idea {\n  id          String       @id @default(uuid())\n  title       String\n  description String       @db.Text\n  authorId    String\n  author      User         @relation(fields: [authorId], references: [id])\n  votes       Int          @default(0)\n  status      String // \"new\", \"review\", \"approved\", \"rejected\"\n  createdAt   DateTime     @default(now())\n  updatedAt   DateTime     @updatedAt\n  experiments Experiment[]\n\n  @@map(\"ideas\")\n}\n\nmodel Experiment {\n  id        String    @id @default(uuid())\n  ideaId    String\n  idea      Idea      @relation(fields: [ideaId], references: [id])\n  title     String\n  status    String // \"planning\", \"in-progress\", \"completed\", \"cancelled\"\n  progress  Int       @default(0) // 0-100\n  startDate DateTime?\n  endDate   DateTime?\n  results   Json? // { impact: \"high\", metrics: {...} }\n  learnings String?   @db.Text\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n\n  @@map(\"experiments\")\n}\n\n// ============================================================================\n// Skills Matrix\n// ============================================================================\n\nmodel Skill {\n  id               String            @id @default(uuid())\n  name             String\n  category         String // \"technical\", \"soft\", \"domain\"\n  description      String?\n  importance       String // \"critical\", \"high\", \"medium\", \"low\"\n  createdAt        DateTime          @default(now())\n  updatedAt        DateTime          @updatedAt\n  userSkills       UserSkill[]\n  skillGaps        SkillGap[]\n  developmentPlans DevelopmentPlan[]\n\n  @@map(\"skills\")\n}\n\nmodel UserSkill {\n  id           String   @id @default(uuid())\n  userId       String\n  user         User     @relation(fields: [userId], references: [id])\n  skillId      String\n  skill        Skill    @relation(fields: [skillId], references: [id])\n  proficiency  Int // 1-5\n  interest     String // \"high\", \"medium\", \"low\"\n  lastAssessed DateTime @default(now())\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  @@unique([userId, skillId])\n  @@map(\"user_skills\")\n}\n\nmodel SkillGap {\n  id           String   @id @default(uuid())\n  skillId      String\n  skill        Skill    @relation(fields: [skillId], references: [id])\n  teamId       String? // Optional link to team/department\n  currentLevel Float\n  targetLevel  Float\n  impact       String // \"critical\", \"high\", \"medium\", \"low\"\n  status       String // \"identified\", \"addressing\", \"resolved\"\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  @@map(\"skill_gaps\")\n}\n\nmodel DevelopmentPlan {\n  id        String    @id @default(uuid())\n  userId    String\n  user      User      @relation(fields: [userId], references: [id])\n  skillId   String\n  skill     Skill     @relation(fields: [skillId], references: [id])\n  type      String // \"course\", \"mentorship\", \"project\"\n  status    String // \"planned\", \"in-progress\", \"completed\"\n  progress  Int       @default(0)\n  dueDate   DateTime?\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n\n  @@map(\"development_plans\")\n}\n"
}

